head.script:
// ===== DEBUG MARKERS START =====
(function () {
    var runId = "DAMDBG-" + Date.now();
    window.__DAM_RUN_ID = runId;

    console.log("[DAM][M0] script-evaluated", runId, "href=", location.href);

    scwin.onpageload = function () {
        console.log("[DAM][M1] onpageload-fired", runId);

        try {
            var tab = $p.getComponentById("tab_main");
            console.log("[DAM][M2] tab_main-exists?", !!tab, tab ? ("id=" + tab.id) : "null");
        } catch (e) {
            console.error("[DAM][E2] get tab_main failed", e);
        }

        scwin._setActive(0);
    };

    scwin._setActive = function (idx) {
        console.log("[DAM][M3] _setActive called idx=", idx);

        var ids = ["btn_navDashboard", "btn_navFileBrowser", "btn_navAssetDetails", "btn_navVersionControl"];
        for (var i = 0; i < ids.length; i++) {
            var comp = $p.getComponentById(ids[i]);
            console.log("[DAM][M3.1] nav-comp", ids[i], !!comp);
            if (comp) comp.removeClass("dam-active");
        }

        var activeComp = $p.getComponentById(ids[idx]);
        if (activeComp) activeComp.addClass("dam-active");

        var titleComp = $p.getComponentById("txt_pageTitle");
        console.log("[DAM][M3.2] title-comp?", !!titleComp);
        if (titleComp) titleComp.setLabel(["Dashboard","File Browser","Asset Details","Version Control"][idx]);

        scwin._switchTab(idx, 0);
    };

    scwin._switchTab = function (idx, attempt) {
        var tab = $p.getComponentById("tab_main");
        console.log("[DAM][M4] _switchTab attempt=", attempt, "tab?", !!tab);

        if (tab) {
            console.log(
                "[DAM][M4.1] methods:",
                "setSelectedTabIndex=", typeof tab.setSelectedTabIndex,
                "setSelectedTab=", typeof tab.setSelectedTab
            );
        }

        try {
            if (tab && typeof tab.setSelectedTabIndex === "function") {
                tab.setSelectedTabIndex(idx);
                console.log("[DAM][M5] setSelectedTabIndex OK idx=", idx);
                return;
            }
            if (tab && typeof tab.setSelectedTab === "function") {
                tab.setSelectedTab(idx);
                console.log("[DAM][M5] setSelectedTab OK idx=", idx);
                return;
            }
        } catch (e) {
            console.error("[DAM][E5] switchTab failed", e);
        }

        if (attempt < 15) {
            setTimeout(function () { scwin._switchTab(idx, attempt + 1); }, 120);
        } else {
            console.error("[DAM][E6] tab_main not ready after retries");
        }
    };

    scwin.btn_navDashboard_onclick = function () {
        console.log("[DAM][M6] click Dashboard");
        scwin._setActive(0);
    };

    scwin.btn_navFileBrowser_onclick = function () {
        console.log("[DAM][M6] click FileBrowser BEFORE redirect");
        scwin._setActive(1);

        // Nếu test redirect thì giữ dòng này:
        // location.href = "websquare/websquare.html?w2xPath=/cm/dam/main/file_browser.xml";
    };
})();
